import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const shipmentSchema = z.object({
  trackingNumber: z.string(),
  status: z.string(),
  origin: z.string(),
  destination: z.string(),
  weight: z.number(),
  dimensions: z.string(),
});

type ShipmentFormData = z.infer<typeof shipmentSchema>;

interface ShipmentFormProps {
  onSubmit: (data: ShipmentFormData) => Promise<void>;
  initialData?: Partial<ShipmentFormData>;
  isEdit?: boolean;
}

export default function ShipmentForm({ onSubmit, initialData, isEdit = false }: ShipmentFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const {
    register,
    handleSubmit,
    formState: { errors },
  } = useForm<ShipmentFormData>({
    resolver: zodResolver(shipmentSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: ShipmentFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-4">

        <div>
          <label htmlFor="trackingNumber" className="block text-sm font-medium text-gray-700 mb-1">
            Trackingnumber
          </label>
          <input
            {...register('trackingNumber')}
            type="text"
            id="trackingNumber"
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
          {errors.trackingNumber && (
            <p className="mt-1 text-sm text-red-600">{errors.trackingNumber.message}</p>
          )}
        </div>

        <div>
          <label htmlFor="status" className="block text-sm font-medium text-gray-700 mb-1">
            Status
          </label>
          <select
            {...register('status')}
            id="status"
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          >
            <option value="booked">Booked</option>
            <option value="picked">Picked</option>
            <option value="intransit">Intransit</option>
            <option value="outfordelivery">Outfordelivery</option>
            <option value="delivered">Delivered</option>
          </select>
        </div>

        <div>
          <label htmlFor="weight" className="block text-sm font-medium text-gray-700 mb-1">
            Weight
          </label>
          <input
            {...register('weight', { valueAsNumber: true })}
            type="number"
            id="weight"
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>

      <button
        type="submit"
        disabled={isSubmitting}
        className="w-full py-2 px-4 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
      >
        {isSubmitting ? (
          <span className="flex items-center justify-center">
            <Loader2 className="w-5 h-5 mr-2 animate-spin" />
            {isEdit ? 'Updating...' : 'Creating...'}
          </span>
        ) : (
          isEdit ? 'Update Shipment' : 'Create Shipment'
        )}
      </button>
    </form>
  );
}
