// composables/useApi.ts
import { ref, computed } from 'vue'

interface UseApiOptions<T> {
  immediate?: boolean
  initialData?: T
  onSuccess?: (data: T) => void
  onError?: (error: Error) => void
}

export function useApi<T>(
  fetcher: () => Promise<T>,
  options: UseApiOptions<T> = {}
) {
  const { immediate = false, initialData, onSuccess, onError } = options

  const data = ref<T | undefined>(initialData) as Ref<T | undefined>
  const error = ref<Error | null>(null)
  const isLoading = ref(false)

  const isError = computed(() => error.value !== null)
  const isSuccess = computed(() => data.value !== undefined && !error.value)

  async function execute() {
    isLoading.value = true
    error.value = null

    try {
      const result = await fetcher()
      data.value = result
      onSuccess?.(result)
      return result
    } catch (e) {
      const err = e instanceof Error ? e : new Error(String(e))
      error.value = err
      onError?.(err)
      throw err
    } finally {
      isLoading.value = false
    }
  }

  function reset() {
    data.value = initialData
    error.value = null
    isLoading.value = false
  }

  if (immediate) {
    execute()
  }

  return {
    data,
    error,
    isLoading,
    isError,
    isSuccess,
    execute,
    reset,
  }
}

// Usage example:
// const { data: users, isLoading, execute } = useApi(
//   () => $fetch('/api/users'),
//   { immediate: true }
// )
