import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const replySchema = z.object({
  content: z.string().optional(),
  likes: z.number().min(0),
  isAcceptedAnswer: z.boolean().default(false),
});

type ReplyFormData = z.infer<typeof replySchema>;

interface ReplyFormProps {
  initialData?: Partial<ReplyFormData>;
  onSubmit: (data: ReplyFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function ReplyForm({ initialData, onSubmit, isEdit = false }: ReplyFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<ReplyFormData>({
    resolver: zodResolver(replySchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: ReplyFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          <div className="col-span-2">
            <label className="block text-sm font-medium text-gray-700 mb-1">Content</label>
            <textarea {...register("content")} rows={4} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Likes</label>
            <input {...register("likes", { valueAsNumber: true })} type="number" step="any" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div className="flex items-center">
            <input {...register("isAcceptedAnswer")} type="checkbox" className="w-4 h-4 text-blue-600 rounded" />
            <label className="ml-2 text-sm text-gray-700">Isacceptedanswer</label>
          </div>
      </div>

      <div className="flex justify-end space-x-4">
        <button type="button" className="px-4 py-2 border rounded-lg hover:bg-gray-50">
          Cancel
        </button>
        <button
          type="submit"
          disabled={isSubmitting}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center"
        >
          {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
          {isEdit ? 'Update' : 'Create'} Reply
        </button>
      </div>
    </form>
  );
}
