import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { Loader2 } from 'lucide-react';

const dentalAppointmentSchema = z.object({
  scheduledAt: z.string(),
  treatment: z.string().min(1, "Treatment is required"),
  status: z.enum(["scheduled", "completed", "cancelled"]),
  toothNumber: z.string().min(1, "Toothnumber is required"),
  notes: z.string().optional(),
});

type DentalAppointmentFormData = z.infer<typeof dentalAppointmentSchema>;

interface DentalAppointmentFormProps {
  initialData?: Partial<DentalAppointmentFormData>;
  onSubmit: (data: DentalAppointmentFormData) => Promise<void>;
  isEdit?: boolean;
}

export default function DentalAppointmentForm({ initialData, onSubmit, isEdit = false }: DentalAppointmentFormProps) {
  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const { register, handleSubmit, formState: { errors } } = useForm<DentalAppointmentFormData>({
    resolver: zodResolver(dentalAppointmentSchema),
    defaultValues: initialData,
  });

  const handleFormSubmit = async (data: DentalAppointmentFormData) => {
    setIsSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit(handleFormSubmit)} className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Scheduledat</label>
            <input {...register("scheduledAt")} type="datetime-local" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Treatment</label>
            <input {...register("treatment")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.treatment && <p className="text-red-500 text-sm mt-1">{errors.treatment.message}</p>}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
            <select {...register("status")} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500">
              <option value="">Select Status</option>
              <option value="scheduled">Scheduled</option>
              <option value="completed">Completed</option>
              <option value="cancelled">Cancelled</option>
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Toothnumber</label>
            <input {...register("toothNumber")} type="text" className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
            {errors.toothNumber && <p className="text-red-500 text-sm mt-1">{errors.toothNumber.message}</p>}
          </div>

          <div className="col-span-2">
            <label className="block text-sm font-medium text-gray-700 mb-1">Notes</label>
            <textarea {...register("notes")} rows={4} className="w-full px-3 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
          </div>
      </div>

      <div className="flex justify-end space-x-4">
        <button type="button" className="px-4 py-2 border rounded-lg hover:bg-gray-50">
          Cancel
        </button>
        <button
          type="submit"
          disabled={isSubmitting}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 disabled:opacity-50 flex items-center"
        >
          {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
          {isEdit ? 'Update' : 'Create'} DentalAppointment
        </button>
      </div>
    </form>
  );
}
